def find_blank(self, state):
    """
        Find the blank position of current state, which is the 0 element.
        :param state: a 3*3 size list of Integer, stores the current state.
        :return i, j: two Integers, represent the coordinate of the blank block.
        >>> eightPuzzle = EightPuzzle([[2, 3, 4], [5, 8, 1], [6, 0, 7]])
        >>> eightPuzzle.find_blank([[2, 3, 4], [5, 8, 1], [6, 0, 7]])
        (2, 1)
        """
    for i in range(3):
        for j in range(3):
            if state[i][j] == 0:
                return (i, j)
    return (-1, -1)

def process_excel_data(self, N, save_file_name):
    """
        Change the specified column in the Excel file to uppercase
        :param N: int, The serial number of the column that want to change
        :param save_file_name: str, source file name
        :return:(int, str), The former is the return value of write_excel, while the latter is the saved file name of the processed data
        >>> processor = ExcelProcessor()
        >>> success, output_file = processor.process_excel_data(1, 'test_data.xlsx')
        """
    try:
        data = self.read_excel(save_file_name)
        if data is None:
            return (0, '')
        processed_data = []
        for row in data:
            if row is None:
                processed_data.append(row)
                continue
            row_list = list(row)
            if N - 1 < len(row_list) and row_list[N - 1] is not None:
                row_list[N - 1] = str(row_list[N - 1]).upper()
            processed_data.append(tuple(row_list))
        if '.' in save_file_name:
            name_parts = save_file_name.rsplit('.', 1)
            output_file_name = f'{name_parts[0]}_processed.{name_parts[1]}'
        else:
            output_file_name = f'{save_file_name}_processed.xlsx'
        result = self.write_excel(processed_data, output_file_name)
        return (result, output_file_name)
    except Exception as e:
        return (0, '')

def calculate(self, expression):
    """
        Calculate the result of the given postfix expression
        :param expression: string, the postfix expression to be calculated
        :return: float, the calculated result
        >>> expression_calculator = ExpressionCalculator()
        >>> expression_calculator.calculate("2 + 3 * 4")
        14.0

        """
    self.postfix_stack.clear()
    transformed_expression = self.transform(expression)
    self.prepare(transformed_expression)
    eval_stack = deque()
    for token in self.postfix_stack:
        if self.is_operator(token):
            if token == '~':
                if not eval_stack:
                    raise ValueError('Invalid expression: missing operand for unary minus')
                operand = eval_stack.pop()
                result = Decimal(0) - Decimal(operand)
                eval_stack.append(str(result))
            else:
                if len(eval_stack) < 2:
                    raise ValueError('Invalid expression: insufficient operands for operator {}'.format(token))
                second_value = eval_stack.pop()
                first_value = eval_stack.pop()
                result = self._calculate(first_value, second_value, token)
                eval_stack.append(str(result))
        else:
            eval_stack.append(token)
    if len(eval_stack) != 1:
        raise ValueError('Invalid expression: evaluation stack has {} elements instead of 1'.format(len(eval_stack)))
    return float(eval_stack.pop())

def prepare(self, expression):
    """
        Prepare the infix expression for conversion to postfix notation
        :param expression: string, the infix expression to be prepared
        >>> expression_calculator = ExpressionCalculator()
        >>> expression_calculator.prepare("2+3*4")

        expression_calculator.postfix_stack = ['2', '3', '4', '*', '+']
        """
    op_stack = deque()
    arr = list(expression)
    current_index = 0
    count = 0
    i = 0
    while i < len(arr):
        current_char = arr[i]
        if self.is_operator(current_char):
            if count > 0:
                self.postfix_stack.append(''.join(arr[current_index:current_index + count]))
                count = 0
            if current_char == '(':
                op_stack.append(current_char)
            elif current_char == ')':
                while op_stack and op_stack[-1] != '(':
                    self.postfix_stack.append(op_stack.pop())
                op_stack.pop()
            else:
                while op_stack and op_stack[-1] != '(' and self.compare(current_char, op_stack[-1]):
                    self.postfix_stack.append(op_stack.pop())
                op_stack.append(current_char)
            current_index = i + 1
        else:
            count += 1
        i += 1
    if count > 0:
        self.postfix_stack.append(''.join(arr[current_index:current_index + count]))
    while op_stack:
        self.postfix_stack.append(op_stack.pop())

@staticmethod
def is_operator(c):
    """
        Check if a character is an operator in {'+', '-', '*', '/', '(', ')', '%'}
        :param c: string, the character to be checked
        :return: bool, True if the character is an operator, False otherwise
        >>> expression_calculator = ExpressionCalculator()
        >>> expression_calculator.is_operator("+")
        True
        """
    return c in {'+', '-', '*', '\\/', '(', ')', '%'}

@staticmethod
def _calculate(first_value, second_value, current_op):
    """
        Perform the mathematical calculation based on the given operands and operator
        :param first_value: string, the first operand
        :param second_value: string, the second operand
        :param current_op: string, the operator
        :return: decimal.Decimal, the calculated result
        >>> expression_calculator = ExpressionCalculator()
        >>> expression_calculator._calculate("2", "3", "+")
        5.0
        """
    first = Decimal(first_value)
    second = Decimal(second_value)
    if current_op == '+':
        return first + second
    elif current_op == '-':
        return first - second
    elif current_op == '*':
        return first * second
    elif current_op == '/':
        if second == 0:
            raise ZeroDivisionError('Division by zero')
        return first / second
    elif current_op == '%':
        return first % second
    else:
        raise ValueError(f'Unsupported operator: {current_op}')

@staticmethod
def transform(expression):
    """
        Transform the infix expression to a format suitable for conversion
        :param expression: string, the infix expression to be transformed
        :return: string, the transformed expression
        >>> expression_calculator = ExpressionCalculator()
        >>> expression_calculator.transform("2 + 3 * 4")
        "2+3*4"
        """
    expression = re.sub('\\s+', '', expression)
    transformed = []
    i = 0
    while i < len(expression):
        c = expression[i]
        if c == '-':
            if i == 0 or expression[i - 1] in '+-*/%(':
                transformed.append('~')
            else:
                transformed.append(c)
        else:
            transformed.append(c)
        i += 1
    return ''.join(transformed)

def condition_judge(self):
    """
        Judge the condition of the user based on the BMI standard.
        :return: 1 if the user is too fat, -1 if the user is too thin, 0 if the user is normal, int.
        >>> fitnessTracker = FitnessTracker(1.8, 70, 20, "male")
        >>> fitnessTracker.condition_judge()
        -1

        """
    bmi = self.get_BMI()
    bmi_std = None
    for std in self.BMI_std:
        if self.sex in std:
            bmi_std = std[self.sex]
            break
    if bmi_std is None:
        return 0
    if bmi < bmi_std[0]:
        return -1
    elif bmi > bmi_std[1]:
        return 1
    else:
        return 0

def calculate_calorie_intake(self):
    """
        Calculate the calorie intake based on the user's condition and BMR (Basal Metabolic Rate),BMR is calculated based on the user's height, weight, age, and sex,male is10 * self.weight + 6.25 * self.height - 5 * self.age + 5,female is 10 * self.weight + 6.25 * self.height - 5 * self.age - 161, and the calorie intake is calculated based on the BMR and the user's condition,if the user is too fat, the calorie intake is BMR * 1.2, if the user is too thin, the calorie intake is BMR * 1.6, if the user is normal, the calorie intake is BMR * 1.4.
        :return: calorie intake, float.
        >>> fitnessTracker = FitnessTracker(1.8, 70, 20, "male")
        >>> fitnessTracker.calculate_calorie_intake()
        986.0

        """
    if self.sex == 'male':
        BMR = 10 * self.weight + 6.25 * self.height * 100 - 5 * self.age + 5
    else:
        BMR = 10 * self.weight + 6.25 * self.height * 100 - 5 * self.age - 161
    condition = self.condition_judge()
    if condition == 1:
        calorie_intake = BMR * 1.2
    elif condition == -1:
        calorie_intake = BMR * 1.6
    else:
        calorie_intake = BMR * 1.4
    return calorie_intake

def check_winner(self):
    """
        Checks if there is a winner by looking for five in a row in all directions (horizontal, vertical, diagonal).
        return: the symbol of the winning player (either 'X' or 'O') if there is a winner, or None otherwise.
        >>> gomokuGame = GomokuGame(10)
        >>> moves = [(5, 5), (0, 0), (5, 4), (0, 1), (5, 3), (0, 2), (5, 2), (0, 3), (5, 1)]
        >>> for move in moves:
        ...     gomokuGame.make_move(move[0], move[1])
        >>> gomokuGame.check_winner()
        'X'
        """
    directions = [(0, 1), (1, 0), (1, 1), (1, -1)]
    for row in range(self.board_size):
        for col in range(self.board_size):
            if self.board[row][col] != ' ':
                for direction in directions:
                    if self._check_five_in_a_row(row, col, direction):
                        return self.board[row][col]
    return None

def get_employee(self, employee_id):
    """
        Get an employee's information from the HRManagementSystem.
        :param employee_id: The employee's id, int.
        :return: If the employee is already in the HRManagementSystem, returns the employee's information, otherwise, returns False.
        >>> hrManagementSystem = HRManagementSystem()
        >>> hrManagementSystem.employees = {1: {'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}}
        >>> hrManagementSystem.get_employee(1)
        {'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}
        >>> hrManagementSystem.get_employee(2)
        False

        """
    if employee_id in self.employees:
        return self.employees[employee_id]
    else:
        return False

def list_employees(self):
    """
        List all employees' information in the HRManagementSystem.
        :return: A list of all employees' information,dict.
        >>> hrManagementSystem = HRManagementSystem()
        >>> hrManagementSystem.employees = {1: {'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}}
        >>> hrManagementSystem.list_employees()
        {1: {'employee_ID': 1, 'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}}
        """
    result = {}
    for employee_id, employee_data in self.employees.items():
        result[employee_id] = {'employee_ID': employee_id, **employee_data}
    return result

def __format_line_feed(self, text):
    """
        Replace consecutive line breaks with a single line break
        :param text: string with consecutive line breaks
        :return:string, replaced text with single line break
        """
    if text is None:
        return ''
    return re.sub('\\n\\s*\\n+', '\n', text)

def get_octets(self):
    """
        If the IP address is valid, the list of four decimal numbers separated by "." constituting the IP address is returned; otherwise, an empty list is returned
        :return: list
        >>> ipaddress = IPAddress("10.10.10.10")
        >>> ipaddress.get_octets()
        ["10", "10", "10", "10"]
        """
    if self.is_valid():
