def check_winner(self):
    """
        Check if there is a winner on the board in rows, columns and diagonals three directions
        :return: str or None, the mark of the winner ('X' or 'O'), or None if there is no winner yet
        >>> moves = [(1, 0), (2, 0), (1, 1), (2, 1), (1, 2)]
        >>> for move in moves:
        ...     ttt.make_move(move[0], move[1])
        >>> ttt.check_winner()
        'X'
        """
    for row in self.board:
        if row[0] == row[1] == row[2] and row[0] != ' ':
            return row[0]
    for col in range(3):
        if self.board[0][col] == self.board[1][col] == self.board[2][col] and self.board[0][col] != ' ':
            return self.board[0][col]
    if self.board[0][0] == self.board[1][1] == self.board[2][2] and self.board[0][0] != ' ':
        return self.board[0][0]
    if self.board[0][2] == self.board[1][1] == self.board[2][0] and self.board[0][2] != ' ':
        return self.board[0][2]
    return None

def string_to_datetime(self, string):
    """
        Convert the time string to a datetime instance
        :param string: string, string before converting format
        :return: datetime instance
        >>> timeutils.string_to_datetime("2001-7-18 1:1:1")
        2001-07-18 01:01:01
        """
    formats_to_try = ['%Y-%m-%d %H:%M:%S', '%Y-%m-%d %H:%M', '%Y-%m-%d', '%Y/%m/%d %H:%M:%S', '%Y/%m/%d %H:%M', '%Y/%m/%d', '%Y.%m.%d %H:%M:%S', '%Y.%m.%d %H:%M', '%Y.%m.%d', '%d-%m-%Y %H:%M:%S', '%d-%m-%Y %H:%M', '%d-%m-%Y', '%d/%m/%Y %H:%M:%S', '%d/%m/%Y %H:%M', '%d/%m/%Y', '%d.%m.%Y %H:%M:%S', '%d.%m.%Y %H:%M', '%d.%m.%Y', '%Y-%m-%d %H:%M:%S.%f']
    for fmt in formats_to_try:
        try:
            return datetime.datetime.strptime(string, fmt)
        except ValueError:
            continue
    try:
        from dateutil import parser
        return parser.parse(string)
    except ImportError:
        raise ValueError(f'Unable to parse date string: {string}')

def evaluate_expression(self, expression):
    """
        Evaluate a mathematical expression and check if the result is 24.
        :param expression: string, mathematical expression
        :return: bool, True if the expression evaluates to 24, False otherwise
        >>> game = TwentyFourPointGame()
        >>> nums = [4, 3, 6, 6]
        >>> ans = "4*3+6+6"
        >>> ret = game.evaluate_expression(ans)
        True
        """
    try:
        ops = {'+': operator.add, '-': operator.sub, '*': operator.mul, '/': operator.truediv}
        tokens = []
        current = ''
        for char in expression:
            if char.isdigit():
                current += char
            else:
                if current:
                    tokens.append(int(current))
                    current = ''
                if char in ops:
                    tokens.append(char)
        if current:
            tokens.append(int(current))

        def evaluate(tokens):
            i = 0
            while i < len(tokens):
                if tokens[i] == '*':
                    left = tokens[i - 1]
                    right = tokens[i + 1]
                    result = ops['*'](left, right)
                    tokens = tokens[:i - 1] + [result] + tokens[i + 2:]
                    i -= 1
                elif tokens[i] == '/':
                    left = tokens[i - 1]
                    right = tokens[i + 1]
                    if right == 0:
                        return None
                    result = ops['/'](left, right)
                    tokens = tokens[:i - 1] + [result] + tokens[i + 2:]
                    i -= 1
                else:
                    i += 1
            result = tokens[0]
            i = 1
            while i < len(tokens):
                if tokens[i] == '+':
                    result = ops['+'](result, tokens[i + 1])
                elif tokens[i] == '-':
                    result = ops['-'](result, tokens[i + 1])
                i += 2
            return result
        result = evaluate(tokens)
        if result is None:
            return False
        return abs(result - 24) < 1e-10
    except (IndexError, ZeroDivisionError, ValueError, TypeError):
        return False

def get_query_params(self):
    """
        Get the request parameters for the URL
        :return: dict, If successful, return the request parameters of the URL
        >>> urlhandler = URLHandler("https://www.baidu.com/s?wd=aaa&rsv_spt=1#page")
        >>> urlhandler.get_query_params()
        {"wd": "aaa", "rsv_spt": "1"}
        """
    query_params = {}
    path = self.get_path()
    if path:
        query_start = path.find('?')
        if query_start != -1:
            query_string = path[query_start + 1:]
            fragment_start = query_string.find('#')
            if fragment_start != -1:
                query_string = query_string[:fragment_start]
            if query_string:
                params = query_string.split('&')
                for param in params:
                    if '=' in param:
                        key, value = param.split('=', 1)
                        query_params[key] = value
    return query_params

@staticmethod
def fix_path(path):
    """
        Fixes the given path string by removing leading and trailing slashes.
        :param path: str, the path string to fix.
        :return: str, the fixed path string.
        >>> url_path = UrlPath()
        >>> url_path.fix_path('/foo/bar/')
        'foo/bar'
        """
    if not path:
        return ''
    while path.startswith('/') or path.startswith('\\/'):
        if path.startswith('/'):
            path = path[1:]
        else:
            path = path[2:]
    while path.endswith('/') or path.endswith('\\/'):
        if path.endswith('/'):
            path = path[:-1]
        else:
            path = path[:-2]
    return path

@staticmethod
def compute_idf_weight_dict(total_num, number_dict):
    """
        Calculate log(total_num+1/count+1) for each count in number_dict
        :param total_num: int
        :param number_dict: dict
        :return: dict
        >>> num_dict = {'key1':0.1, 'key2':0.5}
        >>> VectorUtil.compute_idf_weight_dict(2, num_dict)
        {'key1': 1.0033021088637848, 'key2': 0.6931471805599453}
        """
    result = {}
    for key, count in number_dict.items():
        result[key] = np.log((total_num + 1) / (count + 1))
    return result

def add_product(self, product_id, name, quantity):
    """
        Add product to inventory and plus the quantity if it has existed in inventory.
        Or just add new product to dict otherwise.
        :param product_id: int
        :param name: str, product name
        :param quantity: int, product quantity
        >>> warehouse.add_product(1, "product1", 3)
        >>> warehouse.inventory
        {1: {'name': 'product1', 'quantity': 3}}
        """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity
    else:
        self.inventory[product_id] = {'name': name, 'quantity': quantity}

def update_product_quantity(self, product_id, quantity):
    """
        According to product_id, add the quantity to the corresponding product in inventory.
        >>> warehouse.add_product(1, "product1", 3)
        >>> warehouse.update_product_quantity(1, -1)
        >>> warehouse.inventory
        {1: {'name': 'product1', 'quantity': 2}}
        """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity

def query(self, weather_list, tmp_units='celsius'):
    """
        Query the weather system for the weather and temperature of the city,and convert the temperature units based on the input parameter.
        :param weather_list: a dictionary of weather information for different cities,dict.
        :param tmp_units: the temperature units to convert to, str.
        :return: the temperature and weather of the city, tuple.
        >>> weatherSystem = WeatherSystem('New York')
        >>> weather_list = {'New York': {'weather': 'sunny','temperature': 27,'temperature units': 'celsius'},'Beijing': {'weather': 'cloudy','temperature': 23,'temperature units': 'celsius'}}
        >>> weatherSystem.query(weather_list)
        (27, 'sunny')

        """
    if self.city not in weather_list:
        return (None, None)
    city_data = weather_list[self.city]
    self.weather = city_data['weather']
    self.temperature = city_data['temperature']
    current_units = city_data['temperature units']
    if tmp_units == 'fahrenheit' and current_units == 'celsius':
        self.temperature = self.celsius_to_fahrenheit()
    elif tmp_units == 'celsius' and current_units == 'fahrenheit':
        self.temperature = self.fahrenheit_to_celsius()
    return (self.temperature, self.weather)

def text2int(self, textnum):
    """
        Convert the word string to the corresponding integer string
        :param textnum: string, the word string to be converted
        :return: string, the final converted integer string
        >>> w2n = Words2Numbers()
        >>> w2n.text2int("thirty-two")
        "32"
        """
    if textnum in self.ordinal_words:
        return str(self.ordinal_words[textnum])
    textnum = textnum.replace('-', ' ')
    words = textnum.lower().split()
    processed_words = []
    for word in words:
        if word in self.ordinal_words:
            processed_words.append(str(self.ordinal_words[word]))
            continue
        found = False
        for ending, replacement in self.ordinal_endings:
            if word.endswith(ending):
                base_word = word[:-len(ending)] + replacement
                if base_word in self.numwords:
                    processed_words.append(base_word)
                    found = True
                    break
        if not found:
            processed_words.append(word)
    current = 0
    result = 0
    for word in processed_words:
        if word.isdigit():
            current += int(word)
        elif word in self.numwords:
            scale, increment = self.numwords[word]
            current = current * scale + increment
            if scale > 100:
                result += current
                current = 0
        elif word == 'and':
            continue
    result += current
    return str(result)

def is_valid_input(self, textnum):
    """
        Check if the input text contains only valid words that can be converted into numbers.
        :param textnum: The input text containing words representing numbers.
        :return: True if input is valid, False otherwise.
        >>> w2n = Words2Numbers()
        >>> w2n.is_valid_input("thirty-two")
        False
        """
    textnum = textnum.replace('-', ' ')
    words = textnum.split()
    if not words:
        return False
    for word in words:
        if word in self.ordinal_words:
            continue
        converted = False
        for ending, replacement in self.ordinal_endings:
            if word.endswith(ending):
                base_word = word[:-len(ending)] + replacement
                if base_word in self.numwords:
                    converted = True
                    break
        if converted:
            continue
        if word not in self.numwords:
            return False
    return True

def create_zip_file(self, files, output_file_name):
    """
        Compress the specified file list into a zip file and place it in the specified path
        :param files:list of string, List of files to compress
        :param output_file_name: string, Specified output path
        :return:True or False, representing whether the compression operation was successful
        >>> zfp = ZipFileProcessor("aaa.zip")
        >>> zfp.create_zip_file(["bbb.txt", "ccc,txt", "ddd.txt"], "output/bcd")
        """
    try:
        output_dir = os.path.dirname(output_file_name)
        if output_dir and (not os.path.exists(output_dir)):
            os.makedirs(output_dir)
        with zipfile.ZipFile(output_file_name, 'w', zipfile.ZIP_DEFLATED) as zipf:
            for file in files:
                if os.path.exists(file):
                    zipf.write(file, os.path.basename(file))
                else:
                    continue
        return True
    except Exception as e:
        print(f'Error creating zip file: {e}')
        return False
